using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup so the file exists before the pool needs it
var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var trainer = new ModelTrainingService(loggerFactory.CreateLogger<ModelTrainingService>());
trainer.TrainAndSave();

// Store the label ordering extracted from the trained model so the controller can map scores
builder.Configuration.AddInMemoryCollection(
    trainer.Labels.Select((label, i) => new KeyValuePair<string, string?>($"ModelLabels:{i}", label)));

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.GetModelPath());

var app = builder.Build();
app.MapControllers();
app.Run();

